const wallet = web3.eth.accounts.privateKeyToAccount(privateKey);

// Function to send ETH transaction
async function sendEthTransaction(toAddress, amount) {
  try {
    const txCount = await web3.eth.getTransactionCount(wallet.address);
    const tx = {
      from: wallet.address,
      to: toAddress,
      value: web3.utils.toWei(amount.toString(), 'ether'),
      gas: '20000',
      gasPrice: web3.utils.toWei('20', 'gwei')
    };
    const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
    const txHash = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
    console.log(`ETH transaction sent to ${toAddress} with hash ${txHash}`);
  } catch (error) {
    console.error('Error sending ETH transaction:', error);
  }
}

